func solve(points [][]int64) int64 {
    MOD := int64(1000000007)
    inv2 := int64(500000004)

    yCount := make(map[int64]int64)
    for _, p := range points {
        y := p[1]
        yCount[y]++
    }

    sumC := int64(0)
    sumC2 := int64(0)
    for cnt := range yCount {
        if cnt < 2 {
            continue
        }
        c := cnt * (cnt - 1) / 2
        sumC += c
        sumC2 += c * c
    }

    total := (sumC * sumC - sumC2) % MOD
    if total < 0 {
        total += MOD
    }
    total = (total * inv2) % MOD
    return total
}
